define("local_pathwaynav/activity_sidebar",["core/log"],(function(log){var SELECTORS={FLOAT_BTN:"#lpw-float-btn",DRAWER:"#lpw-drawer",OVERLAY:"#lpw-overlay",CLOSE_BTN:"#lpw-drawer-close"};var CSS={OPEN:"lpw-drawer-open",OVERLAY_VISIBLE:"lpw-overlay-visible",BTN_HIDDEN:"lpw-float-btn-hidden"};var isOpen=!1;var openDrawer=function(elements){isOpen=!0;elements.drawer.classList.add(CSS.OPEN);elements.drawer.setAttribute("aria-hidden","false");elements.overlay.classList.add(CSS.OVERLAY_VISIBLE);elements.floatBtn.classList.add(CSS.BTN_HIDDEN);elements.closeBtn.focus()};var closeDrawer=function(elements){isOpen=!1;elements.drawer.classList.remove(CSS.OPEN);elements.drawer.setAttribute("aria-hidden","true");elements.overlay.classList.remove(CSS.OVERLAY_VISIBLE);elements.floatBtn.classList.remove(CSS.BTN_HIDDEN);elements.floatBtn.focus()};return{init:function(){var floatBtn=document.querySelector(SELECTORS.FLOAT_BTN);var drawer=document.querySelector(SELECTORS.DRAWER);var overlay=document.querySelector(SELECTORS.OVERLAY);var closeBtn=document.querySelector(SELECTORS.CLOSE_BTN);if(!floatBtn||!drawer||!overlay||!closeBtn){log.debug("local_pathwaynav/activity_sidebar: DOM elements not found.");return}var elements={floatBtn:floatBtn,drawer:drawer,overlay:overlay,closeBtn:closeBtn};floatBtn.addEventListener("click",(function(e){e.preventDefault();openDrawer(elements)}));closeBtn.addEventListener("click",(function(e){e.preventDefault();closeDrawer(elements)}));overlay.addEventListener("click",(function(){closeDrawer(elements)}));document.addEventListener("keydown",(function(e){if(e.key==="Escape"&&isOpen){closeDrawer(elements)}}));floatBtn.addEventListener("keydown",(function(e){if(e.key==="Enter"||e.key===" "){e.preventDefault();openDrawer(elements)}}))}}}));
